module.sampleData:
[{
    "match_id": "sample-match-001",
    "event_id": "sample-match-001",
    "clock": {"minute": 78, "stoppage": 2, "period": "2H"},
    "score": {"home": 1, "away": 1},
    "teams": {
        "home": {"name": "Home FC", "abbreviation": "HME", "logo_url": ""},
        "away": {"name": "Away FC", "abbreviation": "AWY", "logo_url": ""}
    },
    "excitement": {"level": 0.82, "trend": "rising"},
    "last_moment": {
        "type": "goal",
        "team": "home",
        "minute": 78,
        "text": "Goal! Home FC equalise in the 78th minute — stadium erupts."
    },
    "next_update_hint_ms": 500
}]

module.onRender:
// Module renderer options
// id: The id of the widget
// target: The target element to render
// items: The items to render (one CROWDAQ event object per tick; phase-1 expects length 1)
// properties: The properties for the widget

(function () {
    var $root = $(target).find('.crowdaq-widget');
    if ($root.length === 0) { return; }

    // Truncation helper — caps last-moment text to maxMomentLength.
    function truncateText(text, maxLen) {
        if (typeof text !== 'string') { return ''; }
        var limit = parseInt(maxLen, 10);
        if (isNaN(limit) || limit <= 0 || text.length <= limit) { return text; }
        return text.slice(0, limit - 1) + '…';
    }

    // Apply one CROWDAQ event payload to the DOM tree rendered by the stencil.
    function applyEvent(evt) {
        if (!evt || typeof evt !== 'object') { return; }

        var teams = evt.teams || {};
        var score = evt.score || {};
        var excitement = evt.excitement || {};
        var moment = evt.last_moment || {};

        // Score / team labels.
        $root.find('.crowdaq-team-name-home').text((teams.home && teams.home.abbreviation) || (teams.home && teams.home.name) || 'Home');
        $root.find('.crowdaq-team-name-away').text((teams.away && teams.away.abbreviation) || (teams.away && teams.away.name) || 'Away');
        $root.find('.crowdaq-score-home').text(score.home != null ? score.home : 0);
        $root.find('.crowdaq-score-away').text(score.away != null ? score.away : 0);

        // Team logos (best-effort — swap src only when we have a URL).
        if (properties.showTeamLogos && teams.home && teams.home.logo_url) {
            $root.find('.crowdaq-team-logo-home').attr('src', teams.home.logo_url).attr('alt', teams.home.name || '');
        }
        if (properties.showTeamLogos && teams.away && teams.away.logo_url) {
            $root.find('.crowdaq-team-logo-away').attr('src', teams.away.logo_url).attr('alt', teams.away.name || '');
        }

        // Excitement meter — level is 0..1, display as 0.0..10.0.
        var level = parseFloat(excitement.level);
        if (isNaN(level)) { level = 0; }
        var pct = Math.max(0, Math.min(1, level)) * 100;
        $root.find('.crowdaq-excitement-fill').css('width', pct + '%');
        $root.find('.crowdaq-excitement-value').text((level * 10).toFixed(1));
        $root.find('.crowdaq-excitement-meter').attr('aria-valuenow', (level * 10).toFixed(1));
        var trend = excitement.trend || 'flat';
        $root.find('.crowdaq-excitement-trend')
            .attr('data-trend', trend)
            .html(trend === 'rising' ? '&#9650;' : trend === 'falling' ? '&#9660;' : '&bull;');

        // Last notable moment (respect showLastMoment + maxMomentLength).
        if (properties.showLastMoment) {
            var momentText = moment.text || '';
            $root.find('.crowdaq-moment-text').text(truncateText(momentText, properties.maxMomentLength));
        }
    }

    // Apply any preview / cached data first so there's always *something*
    // on screen while we wait for the SSE stream to send the first event.
    if (Array.isArray(items) && items.length > 0) {
        applyEvent(items[0]);
        $root.find('.crowdaq-status').attr('data-state', 'stale').text('cached');
    }

    // Open the SSE stream to the CROWDAQ backend. The actual base URL
    // will be injected by the MVP-widget iter (likely via a module
    // setting or a global exposed by the player); for now we fall back
    // to the sampleData path if no URL is available, which is enough
    // for visual preview in the CMS layout editor.
    var streamBase = (window && window.crowdaqBackendBase) ? window.crowdaqBackendBase : null;
    if (!streamBase || typeof EventSource === 'undefined') {
        $root.find('.crowdaq-status').attr('data-state', 'stale').text('preview');
        return;
    }

    var displayId = (typeof xiboIC !== 'undefined' && xiboIC.get) ? xiboIC.get(id, 'displayId') : '';
    var url = streamBase.replace(/\/+$/, '')
        + '/stream?display_id=' + encodeURIComponent(displayId || '')
        + (properties.eventId ? '&event_id=' + encodeURIComponent(properties.eventId) : '');

    try {
        var es = new EventSource(url);
        es.onopen = function () {
            $root.find('.crowdaq-status').attr('data-state', 'live').text('live');
        };
        es.onmessage = function (msg) {
            try {
                var payload = JSON.parse(msg.data);
                applyEvent(payload);
            } catch (err) {
                // ignore malformed tick; keep last good render
            }
        };
        es.onerror = function () {
            $root.find('.crowdaq-status').attr('data-state', 'disconnected').text('reconnecting');
        };
    } catch (err) {
        $root.find('.crowdaq-status').attr('data-state', 'disconnected').text('offline');
    }
})();
